// Check if there's a WebGLRenderer attached (check for renderer properties)
(() => {
  const c = document.querySelector('canvas');
  // Read a pixel near top-left where background should be
  const ctx = c.getContext('webgl2');
  const pixels = new Uint8Array(4);
  // Try reading from default framebuffer at multiple positions
  ctx.readPixels(10, 10, 1, 1, ctx.RGBA, ctx.UNSIGNED_BYTE, pixels);
  const tl = [...pixels];
  ctx.readPixels(Math.floor(c.width/2), Math.floor(c.height/2), 1, 1, ctx.RGBA, ctx.UNSIGNED_BYTE, pixels);
  const ctr = [...pixels];
  return { topLeft: tl, center: ctr };
})()

